var o=process.env.LLRT_LIMITED_CRYPTO==="1";describe("Symbol.toStringTag",()=>{describe("URL module",()=>{it("URL should have correct Symbol.toStringTag",()=>{let t=new URL("https://example.com");expect(t[Symbol.toStringTag]).toBe("URL"),expect(Object.prototype.toString.call(t)).toBe("[object URL]")}),it("URLSearchParams should have correct Symbol.toStringTag",()=>{let t=new URLSearchParams("foo=bar");expect(t[Symbol.toStringTag]).toBe("URLSearchParams"),expect(Object.prototype.toString.call(t)).toBe("[object URLSearchParams]")})}),describe("Encoding",()=>{it("TextEncoder should have correct Symbol.toStringTag",()=>{let t=new TextEncoder;expect(t[Symbol.toStringTag]).toBe("TextEncoder"),expect(Object.prototype.toString.call(t)).toBe("[object TextEncoder]")}),it("TextDecoder should have correct Symbol.toStringTag",()=>{let t=new TextDecoder;expect(t[Symbol.toStringTag]).toBe("TextDecoder"),expect(Object.prototype.toString.call(t)).toBe("[object TextDecoder]")})}),describe("Abort API",()=>{it("AbortController should have correct Symbol.toStringTag",()=>{let t=new AbortController;expect(t[Symbol.toStringTag]).toBe("AbortController"),expect(Object.prototype.toString.call(t)).toBe("[object AbortController]")}),it("AbortSignal should have correct Symbol.toStringTag",()=>{let e=new AbortController().signal;expect(e[Symbol.toStringTag]).toBe("AbortSignal"),expect(Object.prototype.toString.call(e)).toBe("[object AbortSignal]")})}),describe("Fetch API",()=>{it("Headers should have correct Symbol.toStringTag",()=>{let t=new Headers;expect(t[Symbol.toStringTag]).toBe("Headers"),expect(Object.prototype.toString.call(t)).toBe("[object Headers]")}),it("Request should have correct Symbol.toStringTag",()=>{let t=new Request("https://example.com");expect(t[Symbol.toStringTag]).toBe("Request"),expect(Object.prototype.toString.call(t)).toBe("[object Request]")}),it("Response should have correct Symbol.toStringTag",()=>{let t=new Response;expect(t[Symbol.toStringTag]).toBe("Response"),expect(Object.prototype.toString.call(t)).toBe("[object Response]")}),it("FormData should have correct Symbol.toStringTag",()=>{let t=new FormData;expect(t[Symbol.toStringTag]).toBe("FormData"),expect(Object.prototype.toString.call(t)).toBe("[object FormData]")})}),describe("Blob API",()=>{it("Blob should have correct Symbol.toStringTag",()=>{let t=new Blob(["test"]);expect(t[Symbol.toStringTag]).toBe("Blob"),expect(Object.prototype.toString.call(t)).toBe("[object Blob]")}),it("File should have correct Symbol.toStringTag",()=>{let t=new File(["test"],"test.txt");expect(t[Symbol.toStringTag]).toBe("File"),expect(Object.prototype.toString.call(t)).toBe("[object File]")})}),describe("Crypto API",()=>{it("Crypto should have correct Symbol.toStringTag",()=>{expect(crypto[Symbol.toStringTag]).toBe("Crypto"),expect(Object.prototype.toString.call(crypto)).toBe("[object Crypto]")}),it("SubtleCrypto should have correct Symbol.toStringTag",()=>{expect(crypto.subtle[Symbol.toStringTag]).toBe("SubtleCrypto"),expect(Object.prototype.toString.call(crypto.subtle)).toBe("[object SubtleCrypto]")}),it("CryptoKey should have correct Symbol.toStringTag",async()=>{if(o)return;let t=await crypto.subtle.generateKey({name:"HMAC",hash:"SHA-256"},!1,["sign","verify"]);expect(t[Symbol.toStringTag]).toBe("CryptoKey"),expect(Object.prototype.toString.call(t)).toBe("[object CryptoKey]")})}),describe("Exceptions",()=>{it("DOMException should have correct Symbol.toStringTag",()=>{let t=new DOMException("test","TestError");expect(t[Symbol.toStringTag]).toBe("DOMException"),expect(Object.prototype.toString.call(t)).toBe("[object DOMException]")})})});
